"""MCP server — Quiver Quantitative API (auto-generated by /mcp creator).

Quiver Quant aggregates alternative data: congressional trades, insider
transactions, government contracts, WSB sentiment, lobbying, and more.

Auth: Bearer token via QUIVER_QUANT_KEY env var.
Free tier / demo key returns ~1000 records per endpoint.
Real key: https://www.quiverquant.com/quiverapi/
"""
import json
import logging
import os
import sys
from typing import Optional

import httpx
from dotenv import load_dotenv
from mcp.server.fastmcp import FastMCP

load_dotenv()
logging.basicConfig(level=logging.INFO, format="%(asctime)s %(levelname)s %(message)s", stream=sys.stderr)
logger = logging.getLogger("quiverquant-mcp")

mcp = FastMCP("quiverquant")

_BASE = "https://api.quiverquant.com"
_API_KEY = os.environ.get("QUIVER_QUANT_KEY", "demo")
_HEADERS = {
    "Authorization": f"Bearer {_API_KEY}",
    "Accept": "application/json",
    "User-Agent": "AI.Trader/1.0",
}

if _API_KEY == "demo":
    logger.warning("QUIVER_QUANT_KEY=demo — rate-limited to ~1000 records. Set a real key for full access.")

_client: Optional[httpx.AsyncClient] = None


async def _get_client() -> httpx.AsyncClient:
    global _client
    if _client is None or _client.is_closed:
        _client = httpx.AsyncClient(base_url=_BASE, headers=_HEADERS, timeout=30.0)
    return _client


async def _get(path: str, params: Optional[dict] = None) -> dict | list:
    client = await _get_client()
    try:
        r = await client.get(path, params=params or {})
        r.raise_for_status()
        return r.json()
    except httpx.HTTPStatusError as e:
        return {"error": f"HTTP {e.response.status_code}: {e.response.text[:300]}"}
    except Exception as e:
        return {"error": str(e)}


# ── Congressional Trading ─────────────────────────────────────────────────────

@mcp.tool()
async def get_congress_trades_live() -> str:
    """All recent congressional stock disclosures (STOCK Act filings).

    Returns a list of trades with: Representative, Ticker, Transaction,
    Range, TransactionDate, ReportDate, House, Party, ExcessReturn.
    """
    data = await _get("/beta/live/congresstrading")
    return json.dumps(data, indent=2) if not isinstance(data, dict) or "error" not in data else str(data)


@mcp.tool()
async def get_congress_trades_by_ticker(ticker: str) -> str:
    """Historical congressional trades for a specific stock ticker.

    Args:
        ticker: Stock ticker symbol e.g. AAPL, NVDA, MSFT
    """
    data = await _get(f"/beta/historical/congresstrading/{ticker.upper()}")
    return json.dumps(data, indent=2) if not isinstance(data, dict) or "error" not in data else str(data)


