# ── Generic Explorer ───────────────────────────────────────────────────────────

@mcp.tool()
async def explore_endpoint(path: str) -> str:
    """Fetch any Quiver Quant API endpoint directly.

    Useful for discovering undocumented endpoints or fetching data
    not covered by the specific tools above.

    Args:
        path: API path starting with /beta/ e.g. /beta/live/congresstrading
    """
    data = await _get(path)
    if isinstance(data, list):
        count = len(data)
        keys = list(data[0].keys()) if data else []
        preview = json.dumps(data[:3], indent=2)
        return f"Array: {count} items\nKeys: {keys}\n\nFirst 3:\n{preview}"
    return json.dumps(data, indent=2)


if __name__ == "__main__":
    logger.info("Quiver Quant MCP server starting...")
    mcp.run(transport="stdio")
